import React, { useEffect, useState } from "react";
import { createClient } from "@supabase/supabase-js";
import "./App.css";

const supabase = createClient(
    "https://cnakyamdydqxistdavfg.supabase.co",
    "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9..."
);

const columnOrder = [
    "PROJE ADI",
    "TALEP",
    "TEDARİK",
    "VERİLEMEYEN",
    "TED. %",
    "SPOT",
    "FİLO",
    "TESİSTE",
    "GELECEK",
    "YÜKLENDİ",
    "HEDEF ÜSTÜ SEFER",
    "HEDEF ALTI SEFER",
    "HEDEF SEFER",
    "HEDEFSİZ SEFER",
];

function App() {
    const [data, setData] = useState([]);
    const [odakRows, setOdakRows] = useState([]);
    const [stats, setStats] = useState({ toplam: 0, tedarikEdilen: 0, tedarikEdilmeyen: 0 });

    useEffect(() => {
        async function fetchSupabaseData() {
            const { data, error } = await supabase
                .from("toplu_sonuclar")
                .select("json_data")
                .order("created_at", { ascending: false })
                .limit(1)
                .single();

            if (error) console.error("Supabase error:", error);
            else if (data?.json_data) setData(data.json_data);
        }

        fetchSupabaseData();
    }, []);

    useEffect(() => {
        async function fetchOdakData() {
            const today = new Date().toISOString().split("T")[0];
            const payload = {
                startDate: `${today}T00:00:00`,
                endDate: `${today}T23:59:59`,
                userId: 1,
            };

            try {
                const response = await fetch("/api/tmsorders/getall", {
                    method: "POST",
                    headers: {
                        "Content-Type": "application/json",
                        Authorization: "Bearer 49223653afa4b7e22c365...",
                    },
                    body: JSON.stringify(payload),
                });

                const result = await response.json();
                const items = Array.isArray(result.Data) ? result.Data : [];

                // OrderStatu 200 olanları çıkar
                const validItems = items.filter(
                    (item) =>
                        item.OrderStatu !== 200 &&
                        item.TMSVehicleRequestDocumentNo &&
                        item.ProjectName
                );

                // Proje + Pozisyon No benzersiz kombinasyonlar için harita
                const uniqueMap = new Map();

                validItems.forEach((item) => {
                    const key = `${item.ProjectName}__${item.TMSVehicleRequestDocumentNo}`;
                    if (!uniqueMap.has(key)) {
                        uniqueMap.set(key, {
                            ProjectName: item.ProjectName,
                            TMSVehicleRequestDocumentNo: item.TMSVehicleRequestDocumentNo,
                            TMSDespatchDocumentNo: item.TMSDespatchDocumentNo,
                        });
                    }
                });

                const uniqueList = Array.from(uniqueMap.values());

                const tedarikEdilen = uniqueList.filter(
                    (x) => x.TMSDespatchDocumentNo
                ).length;

                setStats({
                    toplam: uniqueList.length,
                    tedarikEdilen,
                    tedarikEdilmeyen: uniqueList.length - tedarikEdilen,
                });

                setOdakRows(uniqueList);
            } catch (err) {
                console.error("Odak API hatası:", err);
            }
        }

        fetchOdakData();
    }, []);

    return (
        <div className="app-container">
            <div className="section">
                <h2>🟢 Supabase: Toplu Sonuçlar</h2>
                {data.length > 0 ? (
                    <div className="table-wrapper">
                        <table className="styled-table">
                            <thead>
                                <tr>
                                    {columnOrder.map((col) => (
                                        <th key={col}>{col}</th>
                                    ))}
                                </tr>
                            </thead>
                            <tbody>
                                {data.slice(1).map((row, idx) => (
                                    <tr key={idx}>
                                        {columnOrder.map((col, i) => {
                                            const value = row[col];
                                            let style = {};
                                            let display = value;

                                            if (col === "TED. %") {
                                                const perc = parseFloat(value);
                                                if (!isNaN(perc)) {
                                                    const pct = Math.round(perc * 100);
                                                    display = `%${pct}`;
                                                    style = {
                                                        color: pct < 70 ? "#e74c3c" : pct < 90 ? "#f39c12" : "#27ae60",
                                                        fontWeight: "bold",
                                                    };
                                                }
                                            }

                                            if (
                                                col === "HEDEF ÜSTÜ SEFER" ||
                                                col === "HEDEF ALTI SEFER" ||
                                                col === "HEDEF SEFER"
                                            ) {
                                                const val = parseFloat(value);
                                                if (!isNaN(val)) {
                                                    display = `${val.toLocaleString("tr-TR")} ₺`;
                                                    if (col === "HEDEF ÜSTÜ SEFER") {
                                                        style = {
                                                            color: val > 0 ? "#27ae60" : "#e74c3c",
                                                            fontWeight: "bold",
                                                        };
                                                    }
                                                }
                                            }

                                            return <td key={i} style={style}>{display}</td>;
                                        })}
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                ) : (
                    <p className="loading">Yükleniyor...</p>
                )}
            </div>

            {/* Odak API Tablosu */}
            <div className="section odak-section">
                <h2>🔵 Odak API: Günlük Tedarik Durumu</h2>
                <p><strong>Toplam Talep:</strong> {stats.toplam}</p>
                <p><strong>Tedarik Edilen:</strong> {stats.tedarikEdilen}</p>
                <p><strong>Tedarik Edilmeyen:</strong> {stats.tedarikEdilmeyen}</p>

                <table className="styled-table">
                    <thead>
                        <tr>
                            <th>Project Name</th>
                            <th>Vehicle Request No</th>
                            <th>Despatch No</th>
                        </tr>
                    </thead>
                    <tbody>
                        {odakRows.map((item, idx) => {
                            const showProject = idx === 0 || item.ProjectName !== odakRows[idx - 1].ProjectName;
                            return (
                                <tr key={idx}>
                                    <td>{showProject ? item.ProjectName : ""}</td>
                                    <td>{item.TMSVehicleRequestDocumentNo}</td>
                                    <td style={{
                                        color: item.TMSDespatchDocumentNo ? "#27ae60" : "#e74c3c"
                                    }}>
                                        {item.TMSDespatchDocumentNo || "TEDARİK EDİLMEDİ"}
                                    </td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            </div>
        </div>
    );
}

export default App;
